// EmployeeDataStore.java
package com.hr.data;

import com.hr.model.Employee;
import com.hr.model.PerformanceReview;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.stream.Collectors;

public class EmployeeDataStore {
    private static EmployeeDataStore instance;
    private final Map<Integer, Employee> employees = new ConcurrentHashMap<>();
    private final Map<Integer, List<PerformanceReview>> reviews = new ConcurrentHashMap<>();
    private final AtomicInteger reviewIdCounter = new AtomicInteger(1000);

    private EmployeeDataStore() {
        initializeSampleData();
    }

    public static synchronized EmployeeDataStore getInstance() {
        if (instance == null) {
            instance = new EmployeeDataStore();
        }
        return instance;
    }

    private void initializeSampleData() {
        employees.put(1001, new Employee(1001, "John", "Smith", "Engineering", "Senior Developer", 95000.0, "ACTIVE", new Date()));
        employees.put(1002, new Employee(1002, "Jane", "Doe", "Marketing", "Marketing Manager", 85000.0, "ACTIVE", new Date()));
        employees.put(1003, new Employee(1003, "Bob", "Johnson", "Finance", "Financial Analyst", 75000.0, "ACTIVE", new Date()));
        employees.put(1004, new Employee(1004, "Alice", "Williams", "Engineering", "Tech Lead", 110000.0, "ACTIVE", new Date()));
        employees.put(1005, new Employee(1005, "Charlie", "Brown", "HR", "HR Specialist", 65000.0, "ACTIVE", new Date()));
    }

    public Employee getEmployee(int employeeId) {
        return employees.get(employeeId);
    }

    public List<Employee> getAllEmployees() {
        return new ArrayList<>(employees.values());
    }

    public List<Employee> getActiveEmployees() {
        return employees.values().stream()
                .filter(e -> "ACTIVE".equals(e.getStatus()))
                .collect(Collectors.toList());
    }

    public void updateEmployee(Employee employee) {
        employees.put(employee.getEmployeeId(), employee);
    }

    public void addReview(PerformanceReview review) {
        review.setReviewId(reviewIdCounter.incrementAndGet());
        reviews.computeIfAbsent(review.getEmployeeId(), k -> new ArrayList<>()).add(review);
    }

    public List<PerformanceReview> getReviews(int employeeId) {
        return reviews.getOrDefault(employeeId, new ArrayList<>());
    }

    public PerformanceReview getLatestReview(int employeeId) {
        List<PerformanceReview> empReviews = reviews.get(employeeId);
        if (empReviews == null || empReviews.isEmpty()) return null;
        return empReviews.stream()
                .max(Comparator.comparing(PerformanceReview::getReviewDate))
                .orElse(null);
    }
}

